// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title CertificatoreMultimetro
 * @notice Contratto per la certificazione on-chain dei dati provenienti da un multimetro IoT.
 *
 * Pattern architetturali applicati:
 *   - Access Restriction Pattern: solo dispositivi autorizzati possono pushare dati.
 *   - Off-Chain Data Storage (Hash-based): nessun dato grezzo on-chain, solo l'hash SHA-256.
 *   - Event-Driven / Asynchronous Trigger: l'allarme guasto è emesso automaticamente dal push.
 *   - Oracle Pattern (Inbound): il dispositivo IoT funge da oracolo che pusha i dati.
 *   - Memoization Pattern: l'hash viene registrato per impedire duplicati.
 *   - State Machine: stato dell'allarme (INATTIVO → ATTIVO → COOLDOWN → RI-VALUTAZIONE).
 *   - Push (Asincrono): il dispositivo pusha periodicamente; il contratto reagisce in autonomia.
 *   - Functional Programming Invariants: sqrt() è pura e deterministica.
 *
 * Ottimizzazioni gas:
 *   - Nessun array/struct in storage (eliminato `registro[]` e `CertificatoMisure`).
 *   - `bytes12` per deviceId anziché `string` (singolo slot, no ABI-encoding dinamico).
 *   - `calldata` per array (niente copia in memory).
 *   - `custom errors` al posto di stringhe in require (~200 gas/byte risparmiati).
 *   - `immutable` per owner (lettura da bytecode: 3 gas vs 2100 gas per SLOAD).
 *   - `unchecked` nei loop (skip overflow check: ~60 gas per iterazione).
 *   - Anti-aliasing allarmi: struct packed in 1 slot (uint64 + bool = 9 bytes).
 */
contract CertificatoreMultimetro {

    // ──────────────────────────────────────────────
    //  Custom Errors (più economici delle stringhe)
    // ──────────────────────────────────────────────

    /// @notice L'indirizzo chiamante non è il proprietario del contratto.
    error SoloOwner();
    /// @notice Il dispositivo non è autorizzato a inviare dati.
    error DispositivoNonAutorizzato();
    /// @notice L'hash della rilevazione è già stato certificato (memoization preventiva).
    error HashGiaCertificato();

    // ──────────────────────────────────────────────
    //  Stato — Access Restriction Pattern
    // ──────────────────────────────────────────────

    /// @notice Indirizzo del deployer, impostato una sola volta (immutable → lettura da bytecode).
    address public immutable owner;

    /// @notice Mapping degli indirizzi autorizzati a pushare dati (dispositivi IoT).
    mapping(address => bool) public autorizzati;

    // ──────────────────────────────────────────────
    //  Stato — Memoization Pattern (Hash-based)
    // ──────────────────────────────────────────────

    /// @notice Mapping hash → bool: true se l'hash è già stato certificato.
    mapping(bytes32 => bool) public hashEsistenti;

    // ──────────────────────────────────────────────
    //  Eventi — Event-Driven Pattern
    // ──────────────────────────────────────────────

    /// @notice Emesso quando una nuova rilevazione viene certificata con successo (Push Asincrono).
    /// @param deviceId ID del dispositivo (indexed per filtraggio off-chain per dispositivo).
    /// @param timestamp Timestamp Unix della rilevazione.
    /// @param fileHash Hash SHA-256 del JSON completo (indexed per lookup rapido).
    event DatoCertificato(
        bytes12 indexed deviceId,
        uint256 timestamp,
        bytes32 indexed fileHash
    );

    // ──────────────────────────────────────────────
    //  Costruttore
    // ──────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
        autorizzati[msg.sender] = true;
    }

    // ──────────────────────────────────────────────
    //  Modifier — Access Restriction Pattern
    // ──────────────────────────────────────────────

    /// @notice Restringe l'accesso al solo proprietario del contratto.
    modifier soloOwner() {
        if (msg.sender != owner) revert SoloOwner();
        _;
    }

    /// @notice Restringe l'accesso ai soli dispositivi autorizzati.
    modifier soloAutorizzati() {
        if (!autorizzati[msg.sender]) revert DispositivoNonAutorizzato();
        _;
    }

    // ──────────────────────────────────────────────
    //  Funzioni di Gestione — Access Restriction
    // ──────────────────────────────────────────────

    /// @notice Autorizza un nuovo dispositivo a pushare dati. Solo l'owner può chiamarla.
    /// @param _dispositivo Indirizzo del dispositivo da autorizzare.
    function autorizzaDispositivo(address _dispositivo) external soloOwner {
        autorizzati[_dispositivo] = true;
    }

    /// @notice Revoca l'autorizzazione di un dispositivo. Solo l'owner può chiamarla.
    /// @param _dispositivo Indirizzo del dispositivo da revocare.
    function revocaDispositivo(address _dispositivo) external soloOwner {
        autorizzati[_dispositivo] = false;
    }

    // ──────────────────────────────────────────────
    //  Funzione Principale — Push Asincrono (Macchina IoT → Blockchain)
    // ──────────────────────────────────────────────

    /**
     * @notice Certifica una nuova rilevazione dal multimetro.
     * @dev Flusso:
     *   1. Memoization check: se l'hash esiste già, revert.
     *   2. Registra l'hash come certificato.
     *   3. Emette DatoCertificato per notificare il frontend.
     *
     * @param _deviceId   ID del dispositivo (bytes12, es. 0x343843413433333944413834).
     * @param _timestamp  Timestamp Unix della rilevazione.
     * @param _fileHash   Hash SHA-256 dell'intero JSON (calcolato off-chain).
     */
    function certificaRilevazione(
        bytes12 _deviceId,
        uint256 _timestamp,
        bytes32 _fileHash
    ) external soloAutorizzati {
        // 1. Memoization preventiva: impedisce certificazione duplicata
        if (hashEsistenti[_fileHash]) revert HashGiaCertificato();

        // 2. Registra l'hash (Off-Chain Data Storage: salviamo SOLO l'hash)
        hashEsistenti[_fileHash] = true;

        // 3. Notifica il frontend (Event-Driven Pattern)
        emit DatoCertificato(_deviceId, _timestamp, _fileHash);
    }
}

