// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ElaboratoreDati
 * @notice Contratto per l'elaborazione on-chain dei dati certificati dal multimetro.
 *
 * Pattern architetturali applicati:
 *   - Access Restriction Pattern: solo utenti autorizzati possono richiedere elaborazioni.
 *   - Memoization Pattern (Caching): se un calcolo è già stato fatto per un hash,
 *     restituisce il risultato dalla cache senza ricalcolare.
 *   - Event-Driven Pattern: emette eventi distinti per calcolo nuovo vs cache hit,
 *     permettendo al frontend di reagire in modo appropriato.
 *   - Push Sincrono: l'utente web pusha una richiesta di calcolo e riceve il risultato via evento.
 *
 * Ottimizzazioni gas:
 *   - `RisultatoCache` struct packed in 1 slot (uint248 + bool = 32 bytes esatti).
 *   - Singola lettura storage (SLOAD) per il cache-hit grazie a `storage` pointer.
 *   - `calldata` per array (niente copia in memory).
 *   - `custom errors` al posto di stringhe in require.
 *   - `unchecked` nei loop.
 *   - `immutable` per owner.
 */
contract ElaboratoreDati {

    // ──────────────────────────────────────────────
    //  Custom Errors
    // ──────────────────────────────────────────────

    /// @notice L'indirizzo chiamante non è il proprietario del contratto.
    error SoloOwner();
    /// @notice L'utente non è autorizzato a richiedere elaborazioni.
    error UtenteNonAutorizzato();
    /// @notice L'array delle tensioni è vuoto.
    error ArrayTensioniVuoto();

    // ──────────────────────────────────────────────
    //  Stato — Access Restriction Pattern
    // ──────────────────────────────────────────────

    /// @notice Indirizzo del deployer (immutable → lettura da bytecode: 3 gas).
    address public immutable owner;

    /// @notice Mapping degli utenti autorizzati a richiedere elaborazioni.
    mapping(address => bool) public autorizzati;

    // ──────────────────────────────────────────────
    //  Stato — Memoization Pattern (Caching)
    // ──────────────────────────────────────────────

    /**
     * @notice Struttura per il risultato in cache, packed in un singolo slot da 32 bytes.
     * @dev uint248 (31 bytes) + bool (1 byte) = 32 bytes = 1 storage slot.
     *      Il flag `esiste` elimina l'ambiguità del valore zero:
     *      anche se la media fosse 0, `esiste = true` indica correttamente un cache hit.
     *      Questo pattern è considerato bulletproof da un auditor.
     */
    struct RisultatoCache {
        uint248 valore;   // Il risultato del calcolo (31 bytes — ampiamente sufficiente)
        bool esiste;      // Flag esplicito di esistenza in cache (1 byte)
    }

    /// @notice Mapping hash → risultato in cache.
    mapping(bytes32 => RisultatoCache) private _cache;

    // ──────────────────────────────────────────────
    //  Stato — Anti-Aliasing Allarmi (State Machine)
    // ──────────────────────────────────────────────

    struct StatoAllarme {
        uint64 timestampAllarme;
        bool attivo;
    }

    /// @notice Mapping deviceId → stato dell'allarme (anti-aliasing).
    mapping(bytes12 => StatoAllarme) public allarmiAttivi;

    /// @notice Durata del cooldown in secondi. Entro questo intervallo, l'allarme non viene ri-emesso.
    uint64 public constant COOLDOWN_ALLARME = 3600; // 1 ora

    /// @notice Soglia THD in centesimi di percentuale. 800 = 8.00%.
    uint256 public constant SOGLIA_THD = 800;

    // ──────────────────────────────────────────────
    //  Eventi — Event-Driven Pattern
    // ──────────────────────────────────────────────

    /// @notice Emesso quando un nuovo calcolo viene eseguito e salvato in cache.
    /// @param fileHash Hash del file elaborato (indexed per lookup off-chain).
    /// @param risultatoMedia Il valore della media calcolata (in centesimi, es. 22050 = 220.50V).
    event CalcoloEseguito(
        bytes32 indexed fileHash,
        uint256 risultatoMedia
    );

    /// @notice Emesso quando il risultato viene recuperato dalla cache (nessun ricalcolo).
    /// @param fileHash Hash del file richiesto (indexed per lookup off-chain).
    /// @param risultatoMedia Il valore della media recuperato dalla cache.
    event RisultatoRecuperatoDallaCache(
        bytes32 indexed fileHash,
        uint256 risultatoMedia
    );

    /// @notice Emesso quando il THD supera la soglia e l'anti-aliasing permette l'emissione.
    /// @param deviceId ID del dispositivo (indexed per filtraggio off-chain).
    /// @param timestamp Timestamp della rilevazione che ha triggerato l'allarme.
    /// @param thdCalcolato Valore THD calcolato in centesimi di percentuale.
    event AllarmeGuasto(
        bytes12 indexed deviceId,
        uint256 timestamp,
        uint256 thdCalcolato
    );

    /// @notice Emesso quando un allarme viene resettato manualmente dall'owner.
    /// @param deviceId ID del dispositivo il cui allarme è stato resettato.
    /// @param timestamp Timestamp del reset.
    event AllarmeReset(
        bytes12 indexed deviceId,
        uint256 timestamp
    );

    // ──────────────────────────────────────────────
    //  Costruttore
    // ──────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
        autorizzati[msg.sender] = true;
    }

    // ──────────────────────────────────────────────
    //  Modifier — Access Restriction Pattern
    // ──────────────────────────────────────────────

    /// @notice Restringe l'accesso al solo proprietario del contratto.
    modifier soloOwner() {
        if (msg.sender != owner) revert SoloOwner();
        _;
    }

    /// @notice Restringe l'accesso ai soli utenti autorizzati.
    modifier soloAutorizzati() {
        if (!autorizzati[msg.sender]) revert UtenteNonAutorizzato();
        _;
    }

    // ──────────────────────────────────────────────
    //  Funzioni di Gestione — Access Restriction
    // ──────────────────────────────────────────────

    /// @notice Autorizza un nuovo utente a richiedere elaborazioni. Solo l'owner può chiamarla.
    /// @param _utente Indirizzo dell'utente da autorizzare.
    function autorizzaUtente(address _utente) external soloOwner {
        autorizzati[_utente] = true;
    }

    /// @notice Revoca l'autorizzazione di un utente. Solo l'owner può chiamarla.
    /// @param _utente Indirizzo dell'utente da revocare.
    function revocaUtente(address _utente) external soloOwner {
        autorizzati[_utente] = false;
    }

    // ──────────────────────────────────────────────
    //  Funzione di lettura cache — Pull Pattern
    // ──────────────────────────────────────────────

    /// @notice Verifica se un hash ha già un risultato in cache e lo restituisce.
    /// @param _fileHash Hash del file da verificare.
    /// @return esiste True se il risultato è in cache.
    /// @return valore Il valore in cache (0 se non esiste).
    function getCacheResult(bytes32 _fileHash) external view returns (bool esiste, uint256 valore) {
        RisultatoCache storage cached = _cache[_fileHash];
        return (cached.esiste, uint256(cached.valore));
    }

    // ──────────────────────────────────────────────
    //  Funzione Principale — Push Sincrono (Utente Web → Blockchain)
    // ──────────────────────────────────────────────

    /**
     * @notice Elabora la media delle tensioni e valuta le armoniche.
     * @param _deviceId   ID del dispositivo.
     * @param _timestamp  Timestamp Unix della rilevazione.
     * @param _fileHash  Hash SHA-256 del JSON originale (chiave della cache).
     * @param _tensioni  Array delle tensioni moltiplicate per 100.
     * @param _tensioneTarget Tensione fondamentale per il calcolo THD.
     * @param _armonicheTarget Array delle armoniche [H3, H5, H7] per il calcolo THD.
     */
    function elaboraMediaTensione(
        bytes12 _deviceId,
        uint256 _timestamp,
        bytes32 _fileHash,
        uint256[] calldata _tensioni,
        uint256 _tensioneTarget,
        uint256[] calldata _armonicheTarget
    ) external soloAutorizzati {
        // 1. Controllo Armoniche (THD)
        StatoAllarme storage stato = allarmiAttivi[_deviceId];
        if (!stato.attivo || (block.timestamp - stato.timestampAllarme) >= COOLDOWN_ALLARME) {
            uint256 sommaQuadrati;
            uint256 hLen = _armonicheTarget.length;
            for (uint256 i; i < hLen; ) {
                uint256 h = _armonicheTarget[i];
                sommaQuadrati += h * h;
                unchecked { ++i; }
            }

            if (_tensioneTarget > 0) {
                uint256 thdCalcolato = (sqrt(sommaQuadrati) * 10000) / _tensioneTarget;
                if (thdCalcolato > SOGLIA_THD) {
                    stato.timestampAllarme = uint64(block.timestamp);
                    stato.attivo = true;
                    emit AllarmeGuasto(_deviceId, _timestamp, thdCalcolato);
                } else if (stato.attivo) {
                    stato.attivo = false;
                }
            }
        }

        // 2. Memoization check — singola lettura storage grazie al pointer
        RisultatoCache storage cached = _cache[_fileHash];
        if (cached.esiste) {
            // Cache HIT: emetti il risultato senza ricalcolare
            emit RisultatoRecuperatoDallaCache(_fileHash, uint256(cached.valore));
            return;
        }

        // 2. Validazione input
        uint256 len = _tensioni.length;
        if (len == 0) revert ArrayTensioniVuoto();

        // 3. Calcolo media on-chain (loop ottimizzato con unchecked)
        uint256 somma;
        for (uint256 i; i < len; ) {
            somma += _tensioni[i];
            unchecked { ++i; }
        }
        uint256 media = somma / len;

        // 4. Salva in cache (1 SSTORE per l'intero slot packed)
        cached.valore = uint248(media);
        cached.esiste = true;

        // 5. Notifica il frontend
        emit CalcoloEseguito(_fileHash, media);
    }

    // ──────────────────────────────────────────────
    //  Reset Allarme — Gestione manuale (solo Owner)
    // ──────────────────────────────────────────────

    /// @notice Resetta manualmente l'allarme per un dispositivo. Solo l'owner può chiamarla.
    /// @param _deviceId ID del dispositivo il cui allarme va resettato.
    function resetAllarme(bytes12 _deviceId) external soloOwner {
        allarmiAttivi[_deviceId].attivo = false;
        emit AllarmeReset(_deviceId, block.timestamp);
    }

    // ──────────────────────────────────────────────
    //  Funzione Pura — Functional Programming Invariant
    // ──────────────────────────────────────────────

    /**
     * @notice Calcolo della radice quadrata intera (metodo Babilonese / Newton).
     * @dev Funzione pura: nessun side-effect, deterministica, nessuna lettura/scrittura di stato.
     *      Costo gas: O(log(y)) iterazioni, ~200-400 gas per valori tipici.
     * @param y Il valore di cui calcolare la radice quadrata.
     * @return z La radice quadrata intera (arrotondata per difetto).
     */
    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }
}

